suspend fun loadJobDetail(id: String): JobDetailScreen = coroutineScope {
    val main = async { jobRepository.getJob(id) }

    val optional = supervisorScope {
        val status = async { runCatchingCancellable { applicationRepository.status(id) } }
        val related = async { runCatchingCancellable { recommendationRepository.related(id) } }
        status.await() to related.await()
    }

    val job = main.await()
    JobDetailScreen(
        job = job,
        applicationStatus = optional.first.getOrNull(),
        relatedJobs = optional.second.getOrDefault(emptyList()),
        statusError = optional.first.exceptionOrNull()?.toUiError(),
        relatedError = optional.second.exceptionOrNull()?.toUiError()
    )
}

suspend inline fun <T> runCatchingCancellable(
    crossinline block: suspend () -> T
): Result<T> = try {
    Result.success(block())
} catch (e: CancellationException) {
    throw e
} catch (e: Throwable) {
    Result.failure(e)
}

sealed interface AppError {
    data object NetworkUnavailable : AppError
    data object Timeout : AppError
    data object SessionExpired : AppError
    data class Validation(val fields: Map<String, String>) : AppError
    data class Server(val code: String?, val retryable: Boolean) : AppError
    data class Unknown(val cause: Throwable) : AppError
}

fun Throwable.toAppError(): AppError = when (this) {
    is SocketTimeoutException -> AppError.Timeout
    is UnknownHostException -> AppError.NetworkUnavailable
    is HttpException -> if (code() == 401) AppError.SessionExpired
                        else AppError.Server(code().toString(), code() >= 500)
    else -> AppError.Unknown(this)
}

suspend fun <T> retryTransient(
    maxAttempts: Int = 3,
    block: suspend () -> T
): T {
    var delayMs = 300L
    repeat(maxAttempts - 1) {
        try { return block() }
        catch (e: CancellationException) { throw e }
        catch (e: IOException) { delay(delayMs); delayMs *= 2 }
    }
    return block()
}
